import torch
from torchvision import models
import os
import json
from PIL import Image
from torchvision import transforms
from torch.utils.data import Dataset, DataLoader
from sklearn.model_selection import train_test_split
from sklearn.metrics import accuracy_score, classification_report

# Function to download model from URL and load it with torch.load
def load_model(url):
    checkpoint = torch.hub.load_state_dict_from_url(url)
    return checkpoint['model']

# Define custom dataset class
class CustomDataset(Dataset):
    def __init__(self, image_paths, labels, transform=transforms.ToTensor()):
        self.image_paths = image_paths
        self.labels = labels
        self.transform = transform

    def __len__(self):
        return len(self.image_paths)

    def __getitem__(self, idx):
        image = Image.open(self.image_paths[idx])
        label = self.labels[idx]
        if self.transform:
            image = self.transform(image)
        return image, label

# Load custom dataset
image_paths = ['path/to/image1.jpg', 'path/to/image2.jpg']  # Replace with actual paths
labels = [0, 1]  # Replace with actual labels

transform = transforms.Compose([transforms.Resize((224, 224)), transforms.ToTensor()])
dataset = CustomDataset(image_paths, labels, transform)
train_loader, val_loader = train_test_split(dataset, test_size=0.2, random_state=42)

# Load pretrained model
model = load_model('https://download.pytorch.org/models/resnet18-5c106cde.pth')

# Freeze model weights and fine-tune last layer
for param in model.parameters():
    param.requires_grad = False

num_ftrs = model.fc.in_features
model.fc = torch.nn.Linear(num_ftrs, 2)  # Replace with actual number of classes

# Define optimizer and loss function
optimizer = torch.optim.Adam(model.fc.parameters(), lr=0.001)
loss_fn = torch.nn.CrossEntropyLoss()

# Fine-tune model on custom dataset
for epoch in range(5):
    for images, labels in train_loader:
        inputs = images.to(device='cuda')
        targets = labels.to(device='cuda')
        optimizer.zero_grad()
        outputs = model(inputs)
        loss = loss_fn(outputs, targets)
        loss.backward()
        optimizer.step()

    # Evaluate on validation set
    with torch.no_grad():
        val_loss = 0
        correct = 0
        for images, labels in val_loader:
            inputs = images.to(device='cuda')
            targets = labels.to(device='cuda')
            outputs = model(inputs)
            loss = loss_fn(outputs, targets)
            val_loss += loss.item()
            _, predicted = torch.max(outputs, dim=1)
            correct += (predicted == targets).sum().item()

        accuracy = correct / len(val_loader.dataset)
        print(f'Epoch {epoch+1}, Val Loss: {val_loss / len(val_loader)}')
        print(f'Epoch {epoch+1}, Val Acc: {accuracy:.4f}')

# Save fine-tuned model checkpoint
torch.save(model.state_dict(), 'fine_tuned_model.pth')